#!/bin/bash
# Spyre vLLM Benchmark Runner
#
# Reads JSON test configs (generated by generate_test_configs.py) and runs
# vLLM benchmarks. Results are written as JSON files and printed to stdout
# for pod log capture.

set -eo pipefail

SCRIPT_DIR="$(cd "$(dirname "$0")" && pwd)"
REPO_ROOT="$(dirname "$SCRIPT_DIR")"
RESULTS_DIR="${RESULTS_DIR:-$REPO_ROOT/results}"
CONFIG_FILE="${CONFIG_FILE:-$REPO_ROOT/config/benchmark_config.yaml}"
TIMESTAMP=$(date -u +"%Y%m%dT%H%M%SZ")

mkdir -p "$RESULTS_DIR"

# -----------------------------------------------
# Detect benchmark CLI
# -----------------------------------------------
detect_bench_command() {
    if vllm bench --help &>/dev/null; then
        BENCH_CMD="vllm bench"
    elif python3 -m vllm.entrypoints.cli.main bench --help &>/dev/null; then
        BENCH_CMD="python3 -m vllm.entrypoints.cli.main bench"
    else
        BENCH_CMD=""
    fi
    echo "  Bench CLI: ${BENCH_CMD:-LEGACY FALLBACK}"
}

# -----------------------------------------------
# json2args: convert JSON params to CLI args
# -----------------------------------------------
json2args() {
    local json_string=$1
    echo "$json_string" | jq -r '
        to_entries |
        map(
            if .value == true then "--" + (.key | gsub("_"; "-"))
            elif .value == false then ""
            else "--" + (.key | gsub("_"; "-")) + " " + (.value | tostring)
            end
        ) |
        map(select(. != "")) |
        join(" ")
    '
}

# -----------------------------------------------
# Run benchmark tests (latency or throughput)
# -----------------------------------------------
run_benchmark_tests() {
    local test_type=$1
    local test_file=$2
    local pass_count=0
    local fail_count=0
    local total=0

    if [[ ! -f "$test_file" ]]; then
        echo "  WARNING: Test file not found: $test_file"
        return 1
    fi

    total=$(jq '. | length' "$test_file")

    echo ""
    echo "╔════════════════════════════════════════════╗"
    echo "║  ${test_type^^} BENCHMARKS ($total tests)"
    echo "╚════════════════════════════════════════════╝"

    while read -r params; do
        test_name=$(echo "$params" | jq -r '.test_name')
        bench_params=$(echo "$params" | jq -r '.parameters')
        bench_args=$(json2args "$bench_params")

        echo ""
        echo "┌─ [$test_type] $test_name"

        if [[ -n "$BENCH_CMD" ]]; then
            bench_command="$BENCH_CMD $test_type --output-json $RESULTS_DIR/${test_name}.json $bench_args"
        else
            if [[ "$test_type" == "latency" ]]; then
                bench_command="python3 -m vllm.benchmarks.latency --output-json $RESULTS_DIR/${test_name}.json $bench_args"
            elif [[ "$test_type" == "throughput" ]]; then
                bench_command="python3 -m vllm.benchmarks.throughput --output-json $RESULTS_DIR/${test_name}.json $bench_args"
            fi
        fi

        echo "│ Command: $bench_command"
        echo "│"

        # Save command for reproducibility
        jq -n \
            --arg command "$bench_command" \
            --arg device "spyre" \
            --arg timestamp "$TIMESTAMP" \
            '{command: $command, device: $device, timestamp: $timestamp}' \
            > "$RESULTS_DIR/${test_name}.commands"

        if eval "$bench_command" 2>&1; then
            # Print key results inline
            if [[ -f "$RESULTS_DIR/${test_name}.json" ]]; then
                echo "│"
                if [[ "$test_type" == "latency" ]]; then
                    echo "│ Result: $(jq -r '"avg=\(.avg_latency | tostring | .[0:6])s  p50=\(.percentiles."50" | tostring | .[0:6])s  p99=\(.percentiles."99" | tostring | .[0:6])s"' "$RESULTS_DIR/${test_name}.json" 2>/dev/null || echo "see JSON")"
                elif [[ "$test_type" == "throughput" ]]; then
                    echo "│ Result: $(jq -r '"\(.tokens_per_second | tostring | .[0:7]) tok/s  \(.requests_per_second | tostring | .[0:5]) req/s  \(.elapsed_time | tostring | .[0:6])s elapsed"' "$RESULTS_DIR/${test_name}.json" 2>/dev/null || echo "see JSON")"
                fi
            fi
            echo "└─ PASS"
            pass_count=$((pass_count + 1))
        else
            echo "└─ FAIL (exit code: $?)"
            fail_count=$((fail_count + 1))
        fi
    done < <(jq -c '.[]' "$test_file")

    echo ""
    echo "  ${test_type} result: $pass_count passed, $fail_count failed (of $total)"
}

# -----------------------------------------------
# Main
# -----------------------------------------------
main() {
    echo ""
    echo "=========================================="
    echo "  Spyre vLLM Benchmark Suite"
    echo "  Timestamp: $TIMESTAMP"
    echo "=========================================="

    # Check for jq
    if ! command -v jq &>/dev/null; then
        echo "ERROR: jq is required but not found."
        exit 1
    fi

    # Detect which benchmark CLI is available
    detect_bench_command

    # Step 1: Generate test configs from YAML
    echo ""
    echo "=== Generating test configurations ==="
    python3 "$SCRIPT_DIR/generate_test_configs.py" "$CONFIG_FILE" "$RESULTS_DIR"

    # Step 2: Run latency benchmarks
    run_benchmark_tests "latency" "$RESULTS_DIR/latency-tests.json"

    # Step 3: Run throughput benchmarks
    run_benchmark_tests "throughput" "$RESULTS_DIR/throughput-tests.json"

    # Step 4: Collect and summarize results
    echo ""
    echo "=== Collecting results ==="
    python3 "$SCRIPT_DIR/collect_results.py" "$RESULTS_DIR" "$TIMESTAMP" || echo "WARNING: collect_results.py failed (results still available as individual JSONs)"

    # Step 5: Print results to stdout for log capture
    echo ""
    echo "========== BENCHMARK RESULTS (JSON) =========="
    if [[ -f "$RESULTS_DIR/benchmark_summary.json" ]]; then
        cat "$RESULTS_DIR/benchmark_summary.json"
    else
        echo "{\"error\": \"No summary generated\"}"
    fi
    echo ""
    echo "========== END BENCHMARK RESULTS =========="

    # Print individual result JSONs (skip pytorch format — too verbose)
    for f in "$RESULTS_DIR"/*.json; do
        basename_f=$(basename "$f")
        [[ "$basename_f" == *-tests.json ]] && continue
        [[ "$basename_f" == "benchmark_summary.json" ]] && continue
        [[ "$basename_f" == *.pytorch.json ]] && continue
        echo ""
        echo "--- $basename_f ---"
        cat "$f"
    done

    # Print pytorch JSONs (needed for model name extraction by push script)
    for f in "$RESULTS_DIR"/*.pytorch.json; do
        [[ -f "$f" ]] || continue
        basename_f=$(basename "$f")
        echo ""
        echo "--- $basename_f ---"
        cat "$f"
    done

    echo ""
    echo "=========================================="
    echo "  Benchmark run complete: $TIMESTAMP"
    echo "=========================================="
}

main "$@"
